module top_module(
		input  wire  clk,
		input  wire  rst,
		output reg   [2:0] count
	);reg [2:0] obf_reg_count;

	always @(posedge clk) begin
		if (rst) begin
			obf_reg_count <= 3'b0;
		end else begin
			obf_reg_count <= obf_reg_count + 1;
		end
	end

	assign count = obf_reg_count;

endmodule
